UPDATE ai_agent_memory
memory_type = #{memoryType}, title = #{title}, content = #{content}, importance = #{importance}, recall_count = #{recallCount}, lifecycle_state = #{lifecycleState}, pinned = #{pinned}, update_by = #{updateBy}, update_time = #{updateTime},
