mapper.select:
SELECT  FROM ai_agent_memory
WHERE user_login_name = #{userLoginName}
  AND business_system = #{businessSystem}
  AND lifecycle_state = 'active'

    AND (agent_id = #{agentId} OR agent_id IS NULL)

ORDER BY pinned DESC, importance DESC, update_time DESC
LIMIT #{limit}

SELECT  FROM ai_agent_memory
WHERE user_login_name = #{userLoginName}
  AND business_system = #{businessSystem}
  AND lifecycle_state = 'active'
  AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY importance DESC, update_time DESC
LIMIT #{limit}

SELECT  FROM ai_agent_memory
WHERE user_login_name = #{userLoginName}
  AND business_system = #{businessSystem}
  AND lifecycle_state = 'active'
  AND title = #{title}

mapper.delete:
DELETE FROM ai_agent_memory
WHERE lifecycle_state = 'archived'
  AND DATEDIFF(NOW(), update_time) > #{days}

